head.script:
	scwin.initData = {
		"chart" : {
			"chartUnit" : 10,
			"chartIntervalCount" : 5,
		},
		"radDisplayData" : [
			{
				"name" : "소내소비량",
				"tooltip" : "발전량 - 전력거래량 (발전량 데이터가 없는 경우 상세실적에서 제외)"
			}
		],
		"observeEvent" : false
	};

	/**
	 * 화면 초기화에 필요한 로직을 수행한다.
	 * @param
	 * @return
	 */
	scwin.initScreen = function() {
		// 화면초기화 공통 함수 호출
		comLib.initForm($p, "ECSPN1000000", {"initScreenCallback" : scwin.searchDatas});
	};

	/**
	 * 화면 초기 데이터들을 조회한다.
	 * @param
	 * @return
	 */
	scwin.searchDatas = function() {
		// 조회조건 설정
		scwin.initSearchParam();
		// 화면 데이터 조회
		scwin.btnInqire_onclick();

		//ecsLib.setChartResizeObserver(this);
	};

	/**
	 * 조회조건 초기화에 필요한 로직을 수행한다.
	 * @param
	 * @return
	 */
	scwin.initSearchParam = function() {
		dmaSearchParam.set("strtDtD" , utilLib.getCurrentDate("yyyy"));
		dmaSearchParam.set("strtDtM" , String(Number(utilLib.getCurrentDate("yyyy")) - 1));
		dmaSearchParam.set("endDtM" , utilLib.getCurrentDate("yyyy"));
		dmaSearchParam.set("gubun", "Q");
		dmaSearchParam.set("basinCd", "ALL");
		dmaSearchParam.set("setcscCd", "ALL");
		dmaSearchParam.set("elcpwstnCd", "ALL");
	};

	/**
	 * 조회조건에 맞게 data를 조회한다.
	 * @param
	 * @return
	 */
	scwin.btnInqire_onclick = function() {
		var action = "";
		var cnd = radMdBy.getValue();
		var gubun = radGubun.getValue();
		var elcpwstnCd = dmaSearchParam.get("elcpwstnCd");
		if (cnd == "D") {
			var strtDate = dmaSearchParam.get("strtDtD");
			var endDate = dmaSearchParam.get("strtDtD");
			if (String(strtDate).length != 4 || String(endDate).length != 4) {
				// 조회기간이 올바르지 않습니다.
				alert(utilLib.getMessage("ECS.INFO.00011")[0]);
				return;
			} else if (["O"].includes(gubun)) {
				if (elcpwstnCd == "ALL") {
					// 발전소 전체는 지원하지 않습니다. 발전소를 선택해주세요.
					alert("발전소 전체는 지원하지 않습니다. 발전소를 선택해주세요.");
					return;
				}
			}
		} else if (cnd == "M") {
			var strtDate = dmaSearchParam.get("strtDtM");
			var endDate = dmaSearchParam.get("endDtM");
			if (String(strtDate).length != 4 || String(endDate).length != 4) {
				// 조회기간이 올바르지 않습니다.
				alert(utilLib.getMessage("ECS.INFO.00011")[0]);
				return;
			} else if (utilLib.minusYears(strtDate, endDate) > 15 ? true : false) {
				// 조회기간은 {0}을 넘어갈 수 없습니다. 다시 설정해 주세요.
				alert(utilLib.getMessage("ECS.INFO.00012", "15년")[0]);
				return;
			} else if (parseInt(strtDate) > parseInt(endDate)) {
				// 시작년이 종료년보다 클수 없습니다.
				alert(utilLib.getMessage("ECS.INFO.00015")[0]);
				return;
			} else if (["O"].includes(gubun)) {
				// 서비스를 지원하지 않습니다.
				alert("서비스를 지원하지 않습니다.");
				return;
			}
		}

		// 라디오버튼 선택에 따라 단위를 변경한다_231025
		if (["Q", "D", "N"].includes(gubun)) {
			spnGrdUnit.setValue("kWh");
		} else if (["E"].includes(gubun)) {
			spnGrdUnit.setValue("원, VAT별도");
		} else if (["U"].includes(gubun)) {
			spnGrdUnit.setValue("원");
		} else if (["O"].includes(gubun)) {
			spnGrdUnit.setValue("%");
		} else {
			spnGrdUnit.setValue("");
		}

		if (["D", "E"].includes(gubun)) {
			spnComment.setLabel("&emsp;* 한전직접거래 발전소 제외");
		} else if (["N"].includes(gubun)) {
			spnComment.setLabel("&emsp;* 소내소비량 = 발전량 - 전력거래량 (발전량 데이터가 없는 경우 상세실적에서 제외)");
		} else if (["O"].includes(gubun)) {
			spnComment.setLabel("&emsp;* 가동률 = (가동시간 / 24h) × 100");
		} else {
			spnComment.setLabel("");
		}

		// 라디오버튼 선택에 따라 그리드 타이틀을 변경한다_231027
		var name = radGubun.getText();
		var radName = radMdBy.getText();
		var gubunList = ["Q", "D", "N", "E", "U", "O"];
		if (gubunList.includes(gubun)) {
			spnGrdTitle2.setLabel(name);
			spnGrdTitle4.setLabel(name);
			spnGrdTitle5.setLabel("상세실적" + "(" + radName + ")");
			spnGrdTitle6.setLabel("패턴 분석" + "(" + radName + ")");
		}

		// 유역/발전원/발전소 선택에 따라 그리드 타이틀을 변경한다_231108
		var basinData = dltAutoCondition1.getAllJSON();
		var setcscData = dltAutoCondition2.getAllJSON();
		var elcpwstnData = dltAutoCondition3.getAllJSON();
		var basinCd = dmaSearchParam.get("basinCd");
		var setcscCd = dmaSearchParam.get("setcscCd");
		cnd = cnd == "M" ? "mnby" : "daly";

		if (basinCd == "ALL" && setcscCd == "ALL" && elcpwstnCd == "ALL") {
			spnGrdTitle1.setLabel("전체");
			spnGrdTitle3.setLabel("전체");
		} else if (basinCd && setcscCd == "ALL" && elcpwstnCd == "ALL") {
			var basinNm = basinData.find(obj => obj.cmmnCd == basinCd).cmmnCdNm;
			spnGrdTitle1.setLabel(basinNm);
			spnGrdTitle3.setLabel(basinNm);
		} else if (basinCd == "ALL" && setcscCd && elcpwstnCd == "ALL") {
			var setcscNm = setcscData.find(obj => obj.cmmnCd == setcscCd).cmmnCdNm
			spnGrdTitle1.setLabel(setcscNm);
			spnGrdTitle3.setLabel(setcscNm);
		} else if (basinCd == "ALL" && setcscCd == "ALL" && elcpwstnCd) {
			var elcpwstnNm = elcpwstnData.find(obj => obj.cmmnCd == elcpwstnCd).cmmnCdNm
			spnGrdTitle1.setLabel(elcpwstnNm);
			spnGrdTitle3.setLabel(elcpwstnNm);
		} else if (basinCd && setcscCd && elcpwstnCd == "ALL") {
			var setcscNm = setcscData.find(obj => obj.cmmnCd == setcscCd).cmmnCdNm
			spnGrdTitle1.setLabel(setcscNm);
			spnGrdTitle3.setLabel(setcscNm);
		} else if (basinCd == "ALL" && setcscCd && elcpwstnCd) {
			var elcpwstnNm = elcpwstnData.find(obj => obj.cmmnCd == elcpwstnCd).cmmnCdNm
			spnGrdTitle1.setLabel(elcpwstnNm);
			spnGrdTitle3.setLabel(elcpwstnNm);
		} else if (basinCd && setcscCd && elcpwstnCd) {
			var elcpwstnNm = elcpwstnData.find(obj => obj.cmmnCd == elcpwstnCd).cmmnCdNm
			spnGrdTitle1.setLabel(elcpwstnNm);
			spnGrdTitle3.setLabel(elcpwstnNm);
		}

		var ecsBasinDivCd = dmaSearchParam.get("basinCd");
		var ecsSetcscDivCd = dmaSearchParam.get("setcscCd");
		var ecsElcpwstnDivCd = dmaSearchParam.get("elcpwstnCd");

		var queryString = `?strtDt=${strtDate}`;
		queryString += `&endDt=${endDate}`;
		queryString += `&cnd=${cnd}`;
		queryString += `&ecsBasinDivCd=${ecsBasinDivCd}`;
		queryString += `&ecsSetcscDivCd=${ecsSetcscDivCd}`;
		queryString += `&ecsElcpwstnDivCd=${ecsElcpwstnDivCd}`;

		var gubun = radGubun.getValue();
		if (gubun == "Q") {
			action = "pn/prdctnacmslt/retrieve-prdctn-acmslt-elyrs-qy.do";
			scwin.initData.chart.chartUnit = 10;
		} else if (gubun == "D") {
			action = "pn/prdctnacmslt/retrieve-prdctn-acmslt-epwr-delng-qy.do";
			scwin.initData.chart.chartUnit = 10;
		} else if (gubun == "N") {
			action = "pn/prdctnacmslt/retrieve-prdctn-inhouse-cnstqy-upc.do";
			scwin.initData.chart.chartUnit = 10;
		} else if (gubun == "E") {
			action = "pn/prdctnacmslt/retrieve-prdctn-acmslt-elyrs-ern.do";
			scwin.initData.chart.chartUnit = 10;
		} else if (gubun == "U") {
			action = "pn/prdctnacmslt/retrieve-prdctn-acmslt-elyrs-upc.do";
			scwin.initData.chart.chartUnit = 10;
		} else if (gubun == "O") {
			action = "pn/prdctnacmslt/retrieve-prdctn-acmslt-orto.do";
			scwin.initData.chart.chartUnit = 10;
		} else {
			action = "";
		}

		var option = {
			action : action
				+ queryString,
			method : "get",
			resData : dltPrdctnAcmsltList,
			success : "scwin.inqireCallback",
			isShowMeg : false
		};
		ajaxLib.executeAjax($p, option);
	};

	/**
	 * 조회 CallBack 실행한다.
	 * @param
	 * @return
	 */
	scwin.inqireCallback = function() {
		// footer 변경
		var footerObj = grdPrdctnAcmsltList.footerDataObj;
		var footerObjKeys = Object.keys(footerObj);

		var cnd = radMdBy.getValue();
		if (cnd == "D") {
			grdPrdctnAcmsltList.setHeaderValue("hYmd", "일자");
		} else if (cnd == "M") {
			grdPrdctnAcmsltList.setHeaderValue("hYmd", "년도");
		}

		var formatterNm = "ecsLib.dsplZeroFrmt";
		if (["U", "O"].includes(radGubun.getValue())) {
			formatterNm = "scwin.dsplZeroFrmt";
			footerObjKeys.forEach(key => {
				if (footerObj[key].expression && footerObj[key].expression != "") {
					footerObj[key].inputType = "expression";
					footerObj[key].expression = footerObj[key].expression.replace("this.footercolsum", "scwin.upcExpression");
					footerObj[key].displayFormatter = "scwin.dsplFrmt";
					footerObj[key].formatter.userFunc = scwin.dsplFrmt;
					if (cnd == "M") {
						// inputType이 얘만 number로 되어 있어 하단에 평균값이 들어가지 않아 차트 구현이 안 돼 주석처리함_0907(whs)
						//footerObj[key].inputType = "number";
						footerObj[key].value = "0";
					} else {
						//footerObj[key].inputType = "expression";
					}
				} else {
					footerObj[key].value = "평균";
				}
			});
			if (cnd == "M") {
				grdPrdctnAcmsltList.setHeaderValue("hTotal", "평균");
				grdPrdctnAcmsltList.setColumnVisible("total", true);
			} else {
				grdPrdctnAcmsltList.setColumnVisible("total", false);
			}
		} else {
			footerObjKeys.forEach(key => {
				if (footerObj[key].expression && footerObj[key].expression != "") {
					footerObj[key].inputType = "expression";
					footerObj[key].expression = footerObj[key].expression.replace("scwin.upcExpression", "this.footercolsum");
					footerObj[key].displayFormatter = "ecsLib.dsplFrmt";
					footerObj[key].formatter.userFunc = ecsLib.dsplFrmt;
				} else {
					footerObj[key].value = "합계";
				}
			});
			grdPrdctnAcmsltList.setHeaderValue("hTotal", "계");
			grdPrdctnAcmsltList.setColumnVisible("total", true);
		}
		grdPrdctnAcmsltList.drawFooter();

		if (grdPrdctnAcmsltList.getAllJSON().length) {
			// 발전단가일 때만 소수점 두자리까지 표시
			Object.keys(grdPrdctnAcmsltList.getAllJSON()[0]).forEach(key => {
				if (key != "ymd" && key != "rowStatus") {
					grdPrdctnAcmsltList.setDisplayFormatter(key, formatterNm);
				}
			});
		}

		// 발전생산량 패턴분석 차트 생성
		scwin.searchChartElyrsPrdqty();
		spnTotalRow.setValue(dltPrdctnAcmsltList.getRowCount());
	};

	scwin.upcExpression = function(col) {
		var datas = grdPrdctnAcmsltList.getAllJSON();
		var cnt = 0;
		return Number((datas.reduce((sum, obj) => {
			if (obj[col]) {
				cnt++;
				sum += Number(obj[col]);
			}
			return sum;
		}, 0) / (cnt ? cnt : 1)).toFixed(5));
	};

	/**
	 * 라디오버튼 선택에 따라 조회연도를 변경한다.
	 * @param
	 * @return
	 */
	scwin.radMdBy_onchange = function() {
		var cnd = radMdBy.getValue();

		if (cnd == "D") {
			grpCalDNm.setStyle("display", "");
			grpCalDBox.setStyle("display", "");
			grpCalMNm.setStyle("display", "none");
			grpCalMBox.setStyle("display", "none");
			document.querySelector(`#${radGubun.getID()} > div:last-child`).style.display = "";
		} else if (cnd == "M") {
			grpCalDNm.setStyle("display", "none");
			grpCalDBox.setStyle("display", "none");
			grpCalMNm.setStyle("display", "");
			grpCalMBox.setStyle("display", "");
			document.querySelector(`#${radGubun.getID()} > div:last-child`).style.display = "none";
			if (radGubun.getValue() == "O") {
				radGubun.setSelectedIndex(0);
			}
		} else {
			return;
		}
	};

	scwin.setRadDisplayTooltip = function(label, index) {
		return scwin.initData.radDisplayData.find(obj => obj.name == label).tooltip;
	};

	/**
	 * 라디오버튼 선택에 따라 단위를 변경한다.
	 * @param
	 * @return
	 */
	scwin.radGubun_onviewchange = function(info) {
		var gubun = info.value;
		var oldGubun = dmaSearchParam.get("gubun");
		dmaSearchParam.set("gubun", gubun);

        /*
		var gunbunQN = ["Q", "N"];
		var gunbunDEU = ["D", "E", "U"];
		var gunbunO = ["O"];
        */
        var gunbunQN = ["Q", "N", "D", "E", "U", "O"];
		var gunbunDEU = ["Q", "N", "D", "E", "U", "O"];
		var gunbunO = ["Q", "N", "D", "E", "U", "O"];

		if (gunbunQN.includes(gubun)) {
			if (!(gunbunQN.includes(gubun) && gunbunQN.includes(oldGubun))) {
				var option = {
					action : "zz/cmmn/retrieve-setcsc.do?cnd=04",
					method : "get",
					resData : dltAutoCondition2,
					success : function(e) {
						var setcscCd = dmaSearchParam.get("setcscCd");
						var idx = dltAutoCondition2.getAllJSON().findIndex(obj => obj.cmmnCd == setcscCd);
						if (idx > -1) {
							dmaSearchParam.set("setcscCd", setcscCd);
							scwin.acbSetcsc_onviewchange({"newValue" : setcscCd});
							acbSetcsc.setSelectedIndex(idx + 1);
						} else {
							dmaSearchParam.set("setcscCd", "ALL");
							scwin.acbSetcsc_onviewchange({"newValue" : "ALL"});
							acbSetcsc.setSelectedIndex(0);
						}
					},
					isShowMeg : false
				};
				ajaxLib.executeAjax($p, option);
			}
		} else if (gunbunDEU.includes(gubun)) {
			if (!(gunbunDEU.includes(gubun) && gunbunDEU.includes(oldGubun))) {
				var option = {
					action : "zz/cmmn/retrieve-setcsc.do?cnd=02",
					method : "get",
					resData : dltAutoCondition2,
					success : function(e) {
						var setcscCd = dmaSearchParam.get("setcscCd");
						var idx = dltAutoCondition2.getAllJSON().findIndex(obj => obj.cmmnCd == setcscCd);
						if (idx > -1) {
							dmaSearchParam.set("setcscCd", setcscCd);
							scwin.acbSetcsc_onviewchange({"newValue" : setcscCd});
							acbSetcsc.setSelectedIndex(idx + 1);
						} else {
							dmaSearchParam.set("setcscCd", "ALL");
							scwin.acbSetcsc_onviewchange({"newValue" : "ALL"});
							acbSetcsc.setSelectedIndex(0);
						}
					},
					isShowMeg : false
				};
				ajaxLib.executeAjax($p, option);
			}
		} else if (gunbunO.includes(gubun)) {
			if (!(gunbunO.includes(gubun) && gunbunO.includes(oldGubun))) {
				var option = {
					action : "zz/cmmn/retrieve-setcsc.do?cnd=05",
					method : "get",
					resData : dltAutoCondition2,
					success : function(e) {
						var setcscCd = dmaSearchParam.get("setcscCd");
						var idx = dltAutoCondition2.getAllJSON().findIndex(obj => obj.cmmnCd == setcscCd);
						if (idx > -1) {
							dmaSearchParam.set("setcscCd", setcscCd);
							scwin.acbSetcsc_onviewchange({"newValue" : setcscCd});
							acbSetcsc.setSelectedIndex(idx + 1);
						} else {
							dmaSearchParam.set("setcscCd", "ALL");
							scwin.acbSetcsc_onviewchange({"newValue" : "ALL"});
							acbSetcsc.setSelectedIndex(0);
						}
					},
					isShowMeg : false
				};
				ajaxLib.executeAjax($p, option);
			}
		} else {
			comLib.alert($p, "서비스 준비중입니다.");
			dmaSearchParam.set("gubun", oldGubun);
			radGubun.setValue(oldGubun);
		}
	};

	/**
	 * 조회박스 선택별 값을 세팅한다.
	 * @param info
	 * @return
	 */
	scwin.acbBasin_onviewchange = function(info) {
		var ecsBasinDivCd = info.newValue;
		dmaSearchParam.set("basinCd", ecsBasinDivCd);
		var ecsSetcscDivCd = dmaSearchParam.get("setcscCd");

		var queryString = `&ecsBasinDivCd=${ecsBasinDivCd}`;
		queryString += `&ecsSetcscDivCd=${ecsSetcscDivCd}`;
		var option = {
			action : "zz/cmmn/retrieve-prdctn-cnd.do?cnd=elcpwstn"
				+ queryString,
			method : "get",
			resData : dltAutoCondition3,
			success : "",
			isShowMeg : false
		};
		ajaxLib.executeAjax($p, option);
		dmaSearchParam.set("elcpwstnCd", "ALL");
	};

	scwin.acbSetcsc_onviewchange = function(info) {
		var ecsSetcscDivCd = info.newValue;
		dmaSearchParam.set("setcscCd", ecsSetcscDivCd);
		var ecsBasinDivCd = dmaSearchParam.get("basinCd");

		var queryString = `&ecsBasinDivCd=${ecsBasinDivCd}`;
		queryString += `&ecsSetcscDivCd=${ecsSetcscDivCd}`;

        /*
		var gunbunQN = ["Q", "N"];
		var gunbunO = ["O"];
        */
        var gunbunQN = [" "];
		var gunbunO = [" "];
		var gubun = dmaSearchParam.get("gubun");
		if (gunbunQN.includes(gubun)) {
			queryString += "&cnd1=04";
		} else if (gunbunO.includes(gubun)) {
			queryString += "&cnd1=05";
		} else {
			queryString += "&cnd1=ALL";
		}
		var option = {
			action : "zz/cmmn/retrieve-prdctn-cnd.do?cnd=elcpwstn"
				+ queryString,
			method : "get",
			resData : dltAutoCondition3,
			success : function(e) {
				var elcpwstnCd = dmaSearchParam.get("elcpwstnCd");
				var idx = dltAutoCondition3.getAllJSON().findIndex(obj => obj.cmmnCd == elcpwstnCd);
				if (idx > -1) {
					dmaSearchParam.set("elcpwstnCd", elcpwstnCd);
					scwin.acbElcpwstn_onviewchange({"newValue" : elcpwstnCd});
					acbElcpwstn.setSelectedIndex(idx + 1);
				} else {
					dmaSearchParam.set("elcpwstnCd", "ALL");
					scwin.acbElcpwstn_onviewchange({"newValue" : "ALL"});
					acbElcpwstn.setSelectedIndex(0);
				}
			},
			isShowMeg : false
		};

		ajaxLib.executeAjax($p, option);
	};

