	/**
	 * 발전생산량 패턴분석 차트를 생성
	 */
	scwin.searchChartElyrsPrdqty = function() {
		var chartVars = "rMateOnLoadCallFunction=" + $p.id + "scwin.chartReadyHandlerElyrsPrdqty";
		rMateChartH5.create($p.id + "chartElyrsPrdqty", grpElyrsPrdqtyChart.getID(), chartVars, "100%", "100%");
	};

	/**
	* 발전생산량 패턴분석 차트 설정
	*/
	scwin.chartReadyHandlerElyrsPrdqty = function(id) {
		var chartData = [];
		var dataList = dltPrdctnAcmsltList.getAllJSON();
		var cnd = radMdBy.getValue();
		//var total = (dataList.reduce((sum, obj) => obj.total ? sum + Number(obj.total) : sum, 0) || 0);
		var maxData = 0;

		if (dataList.length) {
			if (cnd == "D") {
				/*
				for (var idx = 1; idx <= 12; idx++) {
					var sIdx = idx;
					if (sIdx < 10) {
						sIdx = "0" + sIdx;
					}
					prdctnAcmslt = Number(BigInt(grdPrdctnAcmsltList.getFooterData("fMon" + sIdx).toFixed(0)));
					var obj = {
						"month" : sIdx + "월",
						"prdctnAcmslt" : prdctnAcmslt
					}
					chartData.push(obj);
				}
				*/
				for (var idx = 0; idx < dataList.length; idx++) {
					var data = {};
					data["day"] = dataList[idx].ymd;
					for (var idx2 = 1; idx2 < 13; idx2++) {
						var colId = grdPrdctnAcmsltList.getColumnID(idx2);
						//var colUpperId = colId.charAt(0).toUpperCase() + colId.substr(1);
						//if (grdPrdctnAcmsltList.getFooterData("f" + colUpperId)) {
							data["dData" + idx2] = dataList[idx][colId];
						//}
					}
					chartData.push(data);
				}
				maxData = chartData.reduce((max, obj) => {
					for (var idx = 1; idx < Object.keys(obj).length; idx++) {
						max = Math.max(obj["dData" + idx], max);
					}
					return max;
				}, 0);
				//maxData = chartData.reduce((max, obj) => Math.max(obj.prdctnAcmslt, max), 0);
			} else {
				var numDataSets = dataList.length;
				for (var idx = 1; idx < 13; idx++) {
					var monthData = {
						month : idx < 10 ? "0" + idx + "월" : idx + "월"
					};
					// 데이터 갯수만큼 동적 객체(yField 값) 생성_231107
					for (var idx2 = 0; idx2 < numDataSets; idx2++) {
						var key = "yData" + (idx2 + 1);
						monthData[key] = dataList[idx2]["mon" + ("0" + idx).slice(-2)];
					}
					chartData.push(monthData);
				}
				maxData = chartData.reduce((max, obj) => {
					for (var idx = 1; idx < Object.keys(obj).length; idx++) {
						max = Math.max(obj["yData" + idx], max);
					}
					return max;
				}, 0);
				//maxData = chartData.reduce((max, obj) => Math.max(obj.yData1, obj.yData2, max), 0);
			}
		}
		//maxData = chartData.reduce((max, obj) => Math.max(max, 0), 0);
		var chartUnit = Math.max(scwin.initData.chart.chartUnit, Math.pow(10, String(maxData.toFixed(0)).length - 2));
		var interval = Math.ceil((maxData / scwin.initData.chart.chartIntervalCount) / chartUnit) * chartUnit;

		var solidColor1 = ecsLib.getSkinColors().chartSolidColor1;

		var layoutStr =
			'<rMateChart backgroundColor="#FFFFFF"  borderStyle="none">'
			+ '	<Options>'
			+ '		<Legend defaultMouseOverAction="true"/>'
			+ '	</Options>'
			+ '	<NumberFormatter id="numFmt" useThousandsSeparator="true"/>'
			+ '	<Line2DChart showDataTips="true" dataTipDisplayMode="axis">'
			+ '		<horizontalAxis>';
			if (cnd == "D") {
				layoutStr += '<CategoryAxis categoryField="day" padding="0.7"/>';
			} else {
				layoutStr += '<CategoryAxis categoryField="month" padding="0.7"/>';
			}
			layoutStr +=
			'		</horizontalAxis>'
			+ '		<verticalAxis>'
			+ '			<LinearAxis id="vAxis1" interval="' + interval + '" formatter="{numFmt}"/>'
			+ '		</verticalAxis>'
			+ '		<series>';

			// 라디오버튼별 동적  Line2DSeries 생성_231107
			if (cnd == "D") {
				// 라디오버튼별 displayName 이름 설정
				/*
				var grdTitle = spnGrdTitle2.getLabel();
				var displayLabel = "";
				if (grdTitle === "발전단가") {
					var displayLabel = grdTitle + " 월평균(원)";
				} else if (grdTitle === "발전수익") {
					var displayLabel = grdTitle + " 월누적(원)";
				} else {
					var displayLabel =  grdTitle + " 월누적(kWh)";
				}

				layoutStr +=
				'			<Line2DSeries form="curve" yField="prdctnAcmslt" displayName="' + displayLabel + '" itemRenderer="CircleItemRenderer">'
				+ '				<stroke>'
				+ '					<Stroke color="' + solidColor1 + '" weight="3"/>'
				+ '				</stroke>'
				+ '				<lineStroke>'
				+ '					<Stroke color="' + solidColor1 + '" weight="3"/>'
				+ '				</lineStroke>'
				+ '				<showDataEffect>'
				+ '					<SeriesInterpolate duration="1000"/>'
				+ '				</showDataEffect>'
				+ '			</Line2DSeries>';
				*/
				for (var idx = 1; idx < 13; idx++) {
					var sIdx = idx;
					if (sIdx < 10) {
						sIdx = "0" + sIdx;
					}
					// displayName 설정
					var date = sIdx + "월";
					// yField 설정
					layoutStr +=
					'			<Line2DSeries form="curve" yField="dData' + idx + '" displayName="' + date + '" itemRenderer="CircleItemRenderer">'
					+ '				<showDataEffect>'
					+ '					<SeriesInterpolate duration="1000"/>'
					+ '				</showDataEffect>'
					+ '			</Line2DSeries>';
				}
			} else {
				for (var idx = 0; idx < dataList.length; idx++) {
					// displayName 설정
					var year = dataList[idx].ymd;
					// yField 설정
					var sIdx = idx + 1;
					layoutStr +=
					'			<Line2DSeries form="curve" yField="yData' + sIdx + '" displayName="' + year + '" itemRenderer="CircleItemRenderer">'
					+ '				<showDataEffect>'
					+ '					<SeriesInterpolate duration="1000"/>'
					+ '				</showDataEffect>'
					+ '			</Line2DSeries>';
				}
			}

			layoutStr +=
				'		</series>'
				+ '	</Line2DChart>'
				+ '</rMateChart>';

		document.getElementById(id).setLayout(layoutStr);
		document.getElementById(id).setData(chartData);
	};

	//============================================================================================
	// 엑셀
	//============================================================================================
	/**
	 * 그리드의 내용을 엑셀로 다운로드 한다.
	 * @return
	 */
	scwin.btnDownExcel_onclick = function() {
		var menuNm = $p.getComponentById("wfm_title").scope.$p.getComponentById("tbxScreenTitle").getValue();
		var subTitleNm1 = spnGrdTitle3.getValue();
		var subTitleNm2 = spnGrdTitle4.getValue();
		var subTitleNm3 = spnGrdTitle5.getValue();
		var subTitle = subTitleNm1 + " " + subTitleNm2 + " " + subTitleNm3;

		var infoArr = [];
		var infoObj = {
			rowIndex 	: 0,
			colIndex 	: 0,
			rowSpan 	: 0,
			colSpan 	: 14,
			text 		: `${menuNm}_` + `${subTitle}`,
			textAlign 	: "left"
		};
		infoArr.push(infoObj);

		comLib.downloadExcel(grdPrdctnAcmsltList, {
			fileName : `${menuNm}_` + `${subTitle}.xlsx`,
			type : 1,
			autoSizeColumn : true,
			useDataFormat: true,
			applyDataFormat : true
		}, infoArr);
	};
